  ('pukao-6f0ba476-moex-00191', 'pukao-6f0ba476', 'pukao-6f0ba476-moex-112-e38ac4c6', 'sub-pukao-6f0ba476-03', NULL, 'single_choice', '依現行所得稅法，總機構在境內的公司：', '["其境外所得全部免納所得稅", "其境外所得分離課稅", "其境外所得應併同境內所得課徵營利事業所得稅", "其境外所得在新臺幣100萬元以下免納所得稅"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:45+00:00", "source_pdf_sha1": "b5d36143eef6", "answer_pdf_sha1": "cd7aba67d90c", "source_family": "moex-gov-tw", "moex": {"exam_code": "112090", "c": "412", "s": "1004", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "稅務法規概要", "year": "112", "exam_name": "112年公務人員高等考試三級考試暨普通考試", "original_question_number": 5, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('pukao-6f0ba476-moex-00192', 'pukao-6f0ba476', 'pukao-6f0ba476-moex-112-e38ac4c6', 'sub-pukao-6f0ba476-03', NULL, 'single_choice', '依現行法規，營利事業透過財團法人私立學校興學基金會，未指定對特定學校法人或私立學校之 捐款：', '["得全數列為費用", "得以不超過所得額10%為限，列入當年度的費用或損失", "得以不超過所得額20%為限，列入當年度的費用或損失", "得以不超過所得額50%為限，列入當年度的費用或損失"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:45+00:00", "source_pdf_sha1": "b5d36143eef6", "answer_pdf_sha1": "cd7aba67d90c", "source_family": "moex-gov-tw", "moex": {"exam_code": "112090", "c": "412", "s": "1004", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "稅務法規概要", "year": "112", "exam_name": "112年公務人員高等考試三級考試暨普通考試", "original_question_number": 6, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('pukao-6f0ba476-moex-00193', 'pukao-6f0ba476', 'pukao-6f0ba476-moex-112-e38ac4c6', 'sub-pukao-6f0ba476-03', NULL, 'single_choice', '有關營業稅的報繳，下列何者錯誤？', '["除另有規定外，營業人不論有無銷售額，均應填具規定格式之申報書，檢附退抵稅款及其他有 關文件，向主管稽徵機關申報銷售額、應納或溢付營業稅額", "除另有規定外，營業人應以每月為一期，於次月15日前申報繳納營業稅", "依營業稅法第23條規定，查定計算營業稅額之營業人，由主管稽徵機關查定其銷售額及稅額， 每三個月填發繳款書通知繳納一次", "外國之事業、機關、團體、組織在中華民國境內無固定營業場所而有銷售勞務者，應由勞務買 受人於給付報酬之次期開始15日內，就給付額依規定稅率，計算營業稅額繳納之"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:45+00:00", "source_pdf_sha1": "b5d36143eef6", "answer_pdf_sha1": "cd7aba67d90c", "source_family": "moex-gov-tw", "moex": {"exam_code": "112090", "c": "412", "s": "1004", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "稅務法規概要", "year": "112", "exam_name": "112年公務人員高等考試三級考試暨普通考試", "original_question_number": 7, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('pukao-6f0ba476-moex-00194', 'pukao-6f0ba476', 'pukao-6f0ba476-moex-112-e38ac4c6', 'sub-pukao-6f0ba476-03', NULL, 'single_choice', '有關貨物稅的規定，下列何者錯誤？', '["應稅貨物之完稅價格係指產製廠商當月份銷售貨物予批發商之銷售價格", "應稅貨物如為參加展覽，但不出售者，免徵貨物稅", "橡膠輪胎之貨物稅，採從價課徵", "油氣類商品之貨物稅，採從量課徵"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:45+00:00", "source_pdf_sha1": "b5d36143eef6", "answer_pdf_sha1": "cd7aba67d90c", "source_family": "moex-gov-tw", "moex": {"exam_code": "112090", "c": "412", "s": "1004", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "稅務法規概要", "year": "112", "exam_name": "112年公務人員高等考試三級考試暨普通考試", "original_question_number": 8, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('pukao-6f0ba476-moex-00195', 'pukao-6f0ba476', 'pukao-6f0ba476-moex-112-e38ac4c6', 'sub-pukao-6f0ba476-03', NULL, 'single_choice', '依現行法規，下列何者應計入遺產總額？', '["被繼承人自己創作之著作權、發明專利權及藝術品", "被繼承人死亡前五年內，繼承之財產已納遺產稅者", "被繼承人之債權及其他請求權不能收取或行使確有證明者", "被繼承人遺產中屬建造房屋應保留之法定空地部分"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:45+00:00", "source_pdf_sha1": "b5d36143eef6", "answer_pdf_sha1": "cd7aba67d90c", "source_family": "moex-gov-tw", "moex": {"exam_code": "112090", "c": "412", "s": "1004", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "稅務法規概要", "year": "112", "exam_name": "112年公務人員高等考試三級考試暨普通考試", "original_question_number": 9, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('pukao-6f0ba476-moex-00196', 'pukao-6f0ba476', 'pukao-6f0ba476-moex-112-e38ac4c6', 'sub-pukao-6f0ba476-03', NULL, 'single_choice', '有關核課期間的規定，下列何者錯誤？', '["在核課期間內未經發現應徵之稅捐，以後不得再補稅處罰", "依法應由納稅義務人申報繳納之稅捐，已在規定期間內申報，且無故意以詐欺或其他不正當方 法逃漏稅捐者，其核課期間為三年", "依法應由納稅義務人實貼之印花稅，及應由稅捐稽徵機關依稅籍底冊或查得資料核定課徵之稅 捐，其核課期間為五年", "未於規定期間內申報，或故意以詐欺或其他不正當方法逃漏稅捐者，其核課期間為七年"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:45+00:00", "source_pdf_sha1": "b5d36143eef6", "answer_pdf_sha1": "cd7aba67d90c", "source_family": "moex-gov-tw", "moex": {"exam_code": "112090", "c": "412", "s": "1004", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "稅務法規概要", "year": "112", "exam_name": "112年公務人員高等考試三級考試暨普通考試", "original_question_number": 10, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('pukao-6f0ba476-moex-00197', 'pukao-6f0ba476', 'pukao-6f0ba476-moex-112-e38ac4c6', 'sub-pukao-6f0ba476-03', NULL, 'single_choice', '有關房屋稅的相關規定，下列何者錯誤？', '["房屋稅屬於地方稅", "房屋稅每年徵收一次", "政府平價配售之平民住宅免徵房屋稅", "違章建築之房屋應依法課徵房屋稅"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:45+00:00", "source_pdf_sha1": "b5d36143eef6", "answer_pdf_sha1": "cd7aba67d90c", "source_family": "moex-gov-tw", "moex": {"exam_code": "112090", "c": "412", "s": "1004", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "稅務法規概要", "year": "112", "exam_name": "112年公務人員高等考試三級考試暨普通考試", "original_question_number": 11, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('pukao-6f0ba476-moex-00198', 'pukao-6f0ba476', 'pukao-6f0ba476-moex-112-e38ac4c6', 'sub-pukao-6f0ba476-03', NULL, 'single_choice', '關於納稅者權利保護法之敘述，下列何者錯誤？', '["納稅者違反稅法上義務之行為非出於故意或過失者，不予處罰", "納稅者為維持自己及受扶養親屬享有符合人性尊嚴之基本生活所需之費用，不得加以課稅。而 維持基本生活所需之費用，由中央主管機關參照中央主計機關所公布最近一年全國每人可支配 所得中位數百分之五十定之，並於每二年定期檢討", "主管機關應於其網站，主動公開全體國民之所得分配級距與其相應之稅捐負擔比例及持有之不 動產筆數之資訊", "稅捐稽徵機關或財政部賦稅署指定之人員違法調查所取得之證據，不得作為認定課稅或處罰之 基礎"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:45+00:00", "source_pdf_sha1": "b5d36143eef6", "answer_pdf_sha1": "cd7aba67d90c", "source_family": "moex-gov-tw", "moex": {"exam_code": "112090", "c": "412", "s": "1004", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "稅務法規概要", "year": "112", "exam_name": "112年公務人員高等考試三級考試暨普通考試", "original_question_number": 12, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "財稅行政"}'::jsonb, NULL)
